const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.lead_id || !body.client_id || !body.requested_time) return { json: { _empty: true, error: 'lead_id, client_id, requested_time required' } };
return { json: {
  _authorized: true,
  lead_id: body.lead_id,
  client_id: body.client_id,
  requested_time: body.requested_time,
  duration_minutes: body.duration_minutes || 30,
  source_action_id: body.source_action_id || null,
  intake_answers: body.intake_answers || {}
} };

const ctx = $('Validate').item.json;
const leadRow = ($('Fetch Lead').item.json[0]) || ($('Fetch Lead').item.json) || {};
const resp = $input.item.json || {};
const booking = (resp.data && resp.data.id) ? resp.data : (resp.id ? resp : null);
if (!booking) return { json: { _failed: true, error: (resp.error && resp.error.message) || 'Cal.com booking failed', resp_snippet: JSON.stringify(resp).slice(0, 300) } };
return { json: {
  insert_row: {
    lead_id: ctx.lead_id,
    client_id: ctx.client_id,
    scheduled_at: ctx.requested_time,
    duration_minutes: ctx.duration_minutes,
    status: 'scheduled',
    provider: 'cal_com',
    cal_event_id: String(booking.id || booking.uid || ''),
    intake_answers: ctx.intake_answers,
    meeting_link: booking.meetingUrl || booking.location || null,
    source_action_id: ctx.source_action_id
  },
  lead_first_name: leadRow.first_name || (leadRow.full_name || '').split(' ')[0] || 'there',
  lead_email: leadRow.email
} };
